<?php
declare(strict_types=1);
namespace Zoosper\Auth\Repository;
use PDO; use RuntimeException; use Zoosper\Auth\Model\AdminUser;
final readonly class AdminUserRepository { public function __construct(private PDO $pdo){} public function findByEmail(string $email):?AdminUser{$s=$this->pdo->prepare('SELECT * FROM admin_users WHERE email=:email LIMIT 1');$s->execute(['email'=>mb_strtolower($email)]);$r=$s->fetch();return is_array($r)?$this->hydrate($r):null;} public function findById(int $id):?AdminUser{$s=$this->pdo->prepare('SELECT * FROM admin_users WHERE id=:id LIMIT 1');$s->execute(['id'=>$id]);$r=$s->fetch();return is_array($r)?$this->hydrate($r):null;} public function create(string $email,string $name,string $hash,string $roleCode='super_admin'):int{$now=gmdate('Y-m-d H:i:s');$s=$this->pdo->prepare('INSERT INTO admin_users (email,name,password_hash,status,created_at,updated_at) VALUES (:email,:name,:hash,:status,:created,:updated)');$s->execute(['email'=>mb_strtolower($email),'name'=>$name,'hash'=>$hash,'status'=>'active','created'=>$now,'updated'=>$now]);$id=(int)$this->pdo->lastInsertId();$roleId=$this->roleId($roleCode);$l=$this->pdo->prepare('INSERT INTO admin_user_roles (user_id,role_id) VALUES (:u,:r)');$l->execute(['u'=>$id,'r'=>$roleId]);return $id;} public function updateLastLogin(int $id):void{$now=gmdate('Y-m-d H:i:s');$s=$this->pdo->prepare('UPDATE admin_users SET last_login_at=:login, updated_at=:updated WHERE id=:id');$s->execute(['id'=>$id,'login'=>$now,'updated'=>$now]);} private function hydrate(array $r):AdminUser{return new AdminUser((int)$r['id'],(string)$r['email'],(string)$r['name'],(string)$r['password_hash'],(string)$r['status'],$this->permissionsForUser((int)$r['id']));} private function permissionsForUser(int $id):array{$s=$this->pdo->prepare('SELECT DISTINCT p.code FROM admin_permissions p INNER JOIN admin_role_permissions rp ON rp.permission_id=p.id INNER JOIN admin_user_roles ur ON ur.role_id=rp.role_id WHERE ur.user_id=:id ORDER BY p.code');$s->execute(['id'=>$id]);return array_map(fn($r)=>(string)$r['code'],$s->fetchAll());} private function roleId(string $code):int{$s=$this->pdo->prepare('SELECT id FROM admin_roles WHERE code=:code');$s->execute(['code'=>$code]);$id=$s->fetchColumn();if($id===false)throw new RuntimeException('Role does not exist: '.$code);return (int)$id;} }
